// Detect file type from path extension for syntax highlighting
static FileType detect_file_type(const char* path) {
    if (!path) return FileType::Unknown;

    // Find extension
    const char* ext = strrchr(path, '.');
    if (!ext || !ext[1]) return FileType::Unknown;
    ext++;  // Skip dot

    // Fast path: check length first (most extensions are 1-8 chars)
    size_t ext_len = strlen(ext);
    if (ext_len > 8) return FileType::Unknown;

    // Lowercase copy for comparison
    char ext_lower[8];
    for (size_t i = 0; i <= ext_len && i < 7; i++) {
        ext_lower[i] = (ext[i] >= 'A' && ext[i] <= 'Z') ? (char)(ext[i] + 32) : ext[i];
    }

    // C/C++ source files
    if (strcmp(ext_lower, "cpp") == 0 || strcmp(ext_lower, "c") == 0 ||
        strcmp(ext_lower, "cc") == 0 || strcmp(ext_lower, "cxx") == 0) {
        return FileType::Cpp;
    }

    // C/C++ header files (use same lexer)
    if (strcmp(ext_lower, "h") == 0 || strcmp(ext_lower, "hpp") == 0 ||
        strcmp(ext_lower, "hxx") == 0) {
        return FileType::Header;
    }

    // C# source files
    if (strcmp(ext_lower, "cs") == 0) {
        return FileType::CSharp;
    }

    // XAML files
    if (strcmp(ext_lower, "xaml") == 0) {
        return FileType::Xaml;
    }

    // Markdown files
    if (strcmp(ext_lower, "md") == 0) {
        return FileType::Markdown;
    }

    return FileType::Unknown;
}

