namespace DiffPairing {
    // Minimum similarity for two lines to be considered a match (50%)
    // Balances matching modified lines vs avoiding false matches
    constexpr float SIMILARITY_THRESHOLD = 0.5f;

    // If fewer than this percentage of lines match, treat as block replacement (30%)
    // Block replacement outputs all removals then all additions (cleaner for rewrites)
    constexpr size_t BLOCK_REPLACEMENT_THRESHOLD_PERCENT = 30;
}

